const fs = require('fs');
const names = process.argv.slice(2);
for (const name of names) {
  const files = fs.readdirSync('data/chat_history').filter(f => f.includes(name));
  if (files.length === 0) { console.log('NOT FOUND:', name); continue; }
  const data = JSON.parse(fs.readFileSync('data/chat_history/' + files[0], 'utf8'));
  console.log('===== ' + data.name + ' (' + data.totalMessages + ' msgs) =====');
  const msgs = data.messages.reverse();
  for (const m of msgs) {
    const content = m.message?.content?.text?.content;
    if (!content) continue;
    // skip system msgs
    if (content.includes('Since you have read') || content.includes('自动接待将不再触发') ||
        content.includes('Marco大模型翻译') || content.includes('买家有流失风险') ||
        content.includes('一旦离开平台') || content.includes('由于您介入') ||
        content.includes('AI给您生成') || content.includes('You have a visitor') ||
        content.includes('has been pre-screened')) continue;
    const isUs = (m.message?.sender?.uid || '').startsWith('2500000853693');
    const tag = isUs ? 'US' : 'CUST';
    const date = new Date(m.message?.createAt).toISOString().slice(0,10);
    console.log('[' + date + '] ' + tag + ': ' + content);
  }
  console.log('');
